%[text] # Mean-adjusted model
%[text:tableOfContents]{"heading":"**Table of Contents**"}
%%
%[text] ## Housekeeping
clear
close all

import mean.*
%%
%[text] ## Convenience functions
%[text] The `extremesFunc` function compresses any number of samples (draws from the posterior) into two numbers - the minimum and the maximum.
percentiles = [10, 50, 90];

prctileFunc = @(x) prctile(x, percentiles, 2);

extremesFunc = @(x) [min(x, [], 2), max(x, [], 2)];

medianFunc = @(x) median(x, 2) %[output:43a747f9]
%%
%[text] ## Number of Samples
numPresampled = 1000;
%%
%[text] ## Prepare data and a reduced-form model
%[text] The properties specific to the two-step FAVAR are as follows:
%[text] **trendType** – controls the the trend of each endogenous variable. could be
%[text] -     "**constant**" :intercept only
%[text] -     "**time**": intercept + linear
%[text] -     "**quadratic**" : intercept + linear+quadratic \
%[text] **numRegimes** – controls the number of regimes for each endogenous variable.
%[text] **regimeSpans** – controls the periods of each regimes, note that if a regime has more sub periods and is "coming back", the sub periods has to be concatenated
%[text] **bounds** – controls upper and lower bounds for **"constant"** type trends for each regimes. Note that you have to list bounds for each regime also if the bounds are common for the regimes.
%[text] 
%[text] #### **Important notes**
%[text] For this particular model, the user cannot specify any exogenous variables. The only exogenous variables are the selected trends. The intercept property is also missing, as by construction it is assumed that all variables include one.

estimStart = datex.q(1972,1);
estimEnd = datex.q(2020,1);
estimSpan = datex.span(estimStart, estimEnd);

turningPoint1 = datex.q(2008,1);
turningPoint2 = datex.q(2014,4);  

inputTbx = tablex.fromFile("data/SV.csv");

meta = Meta( ...
    endogenousNames=["YER", "HICSA", "STN"], ...
    order=4, ...
    estimationSpan=estimSpan, ...
    trendType = ["time", "constant", "constant"],...
    numRegimes = [2, 2, 1],...    
    regimeSpans = { ...
                    {[datex.span(estimStart, turningPoint1), ...
                      datex.span(datex.shift(turningPoint2, 1), estimEnd)]}, ...
                    {datex.span(datex.shift(turningPoint1, 1), turningPoint2)} ...
                  }, ...
    bounds = {{[]}, {[1 4], [0 2]}, {[2 5]}}, ...              
    identificationHorizon=20 ...
);


%%
%[text] ## Specifying and loading input data

inputTbx = tablex.fromFile("data/SV.csv");
dataH = DataHolder(meta, inputTbx);

%%
%[text] ## Reduced form models
%[text] There is only estimator specific variable
%[text] **ScaleUp** used for scaling up the variance of the estimated constants

estimatorR = estimator.MeanAdjusted(meta,...
    ScaleUp = 100);

modelR = ReducedForm( ...
    meta=meta ...
    , dataHolder=dataH ...
    , estimator=estimatorR ...
);

modelR.Estimator.Settings %[output:1f830a3d]
modelR.initialize();
info = modelR.presample(numPresampled); %[output:18092d5d]
%%
%[text] ## Running Unconditional forecast 
%[text] 
%[text] ### Setting up the forecast range and run the forecast
fcastStart = datex.shift(modelR.Meta.EstimationEnd,1); 
fcastEnd = datex.shift(modelR.Meta.EstimationEnd, 12); 
fcastSpan = datex.span(fcastStart, fcastEnd);

fcastStart, fcastEnd %[output:65db41d9] %[output:889a1635]

fcastTbx1 = modelR.forecast(fcastSpan);
fcastPrctileTbx1 = tablex.apply(fcastTbx1, prctileFunc);
%[text] ### Visualize the unconditional forecast
chartpack.forecastPercentiles( ... %[output:group:93558e64] %[output:0aeaae91] %[output:9ee3a1c9] %[output:49173874]
    fcastPrctileTbx1, modelR, FigureTitle ="Unconditional forecast") %[output:group:93558e64] %[output:0aeaae91] %[output:9ee3a1c9] %[output:49173874]

